### Test Scenarios

1. **Metrics Endpoint Responds**
   ```rust
   #[tokio::test]
   async fn test_metrics_endpoint_responds() {
       let harness = TestHarness::with_config(r#"
           [settings]
           metrics_enabled = true
           metrics_port = 19090
       "#).await;
       harness.start_daemon().await.unwrap();

       let resp = reqwest::get("http://127.0.0.1:19090/metrics").await.unwrap();
