2. **Metrics Reflect Health Check Activity**
   ```rust
   #[tokio::test]
   async fn test_health_check_metrics() {
       let mut harness = TestHarness::new().await;
       harness.add_mock_proxy(MockBehavior::Healthy { latency_ms: 50 }).await;
       harness.start_daemon().await.unwrap();

       // Wait for health checks
       tokio::time::sleep(Duration::from_secs(10)).await;

       let body = fetch_metrics(&harness).await;
       assert!(body.contains("rust_proxy_health_checks_total"));
       assert_metric_value(&body, "rust_proxy_proxy_health", "1");
   }
   ```

3. **Failover Events Tracked**
   ```rust
   #[tokio::test]
   async fn test_failover_metric_increments() {
       let mut harness = failover_test_harness().await;
       trigger_failover(&harness).await;

       let body = fetch_metrics(&harness).await;
       assert!(body.contains("rust_proxy_failovers_total"));
   }
   ```

4. **Metrics Disabled When Configured**
   ```rust
   #[tokio::test]
   async fn test_metrics_disabled() {
       let harness = TestHarness::with_config(r#"
           [settings]
           metrics_enabled = false
       "#).await;
       harness.start_daemon().await.unwrap();

       let result = reqwest::get("http://127.0.0.1:9090/metrics").await;
       assert!(result.is_err() || result.unwrap().status() != 200);
   }
   ```

5. **Prometheus Scrape Compatible**
   ```rust
   #[tokio::test]
   async fn test_prometheus_scrape_format() {
       let harness = metrics_enabled_harness().await;
       let body = fetch_metrics(&harness).await;

       // Verify Prometheus text format
       assert!(body.lines().any(|l| l.starts_with("# HELP ")));
       assert!(body.lines().any(|l| l.starts_with("# TYPE ")));
